import argparse
import json
import logging
import math
import os
import random
from pathlib import Path

import numpy as np
import soundfile as sf
import torch
import torch.nn.functional as F
from sklearn.metrics import roc_curve
from torch.utils.data import DataLoader, Dataset, Sampler, WeightedRandomSampler
from transformers import AutoFeatureExtractor, get_cosine_schedule_with_warmup

from model import build_model

logging.basicConfig(level=logging.WARNING)


def set_seed(seed: int):
    random.seed(seed)
    np.random.seed(seed)
    torch.manual_seed(seed)
    torch.cuda.manual_seed_all(seed)


class JsonlLogger:
    def __init__(self):
        iter_id = os.environ.get('RAB_ITERATION', '0')
        self.path = Path('logs') / f'iter_{iter_id}' / 'metrics.jsonl'
        self.path.parent.mkdir(parents=True, exist_ok=True)

    def log(self, **kwargs):
        with self.path.open('a') as f:
            f.write(json.dumps(kwargs) + '\n')


class LengthBucketBatchSampler(Sampler):
    def __init__(self, lengths, batch_size, shuffle=True):
        self.lengths = np.asarray(lengths)
        self.batch_size = batch_size
        self.shuffle = shuffle

    def __iter__(self):
        idx = np.arange(len(self.lengths))
        if self.shuffle:
            np.random.shuffle(idx)
        chunks = [idx[i:i + self.batch_size * 50] for i in range(0, len(idx), self.batch_size * 50)]
        batches = []
        for chunk in chunks:
            chunk = chunk[np.argsort(self.lengths[chunk])]
            for i in range(0, len(chunk), self.batch_size):
                batches.append(chunk[i:i + self.batch_size].tolist())
        if self.shuffle:
            np.random.shuffle(batches)
        for b in batches:
            yield b

    def __len__(self):
        return math.ceil(len(self.lengths) / self.batch_size)


def discover_data_dir(user_path=None) -> Path:
    candidates = []
    env_path = os.environ.get('RAB_DATA_DIR')
    for p in [user_path, env_path, '/data', '/mnt/data', '/workspace/data', '.']:
        if p:
            candidates.append(Path(p))
    seen = set()
    expanded = []
    for base in candidates:
        try:
            base = base.resolve()
        except Exception:
            pass
        if str(base) in seen:
            continue
        seen.add(str(base))
        expanded.append(base)
        if base.exists() and base.is_dir():
            try:
                for child in base.iterdir():
                    if child.is_dir() and str(child) not in seen:
                        seen.add(str(child))
                        expanded.append(child)
            except Exception:
                pass
    for cand in expanded:
        if (cand / 'train_protocol.txt').exists() and (cand / 'dev_protocol.txt').exists() and (cand / 'train/flac').exists():
            return cand
    for root in [Path('/rab_data'), Path('/workspace'), Path('/')]:
        if not root.exists():
            continue
        try:
            for cand in root.rglob('train_protocol.txt'):
                parent = cand.parent
                if (parent / 'dev_protocol.txt').exists() and (parent / 'train/flac').exists():
                    return parent
        except Exception:
            continue
    raise FileNotFoundError(f'Could not locate dataset root. RAB_DATA_DIR={env_path}, user_path={user_path}')


def parse_protocol(path: Path, audio_dir: Path):
    items = []
    with open(path) as f:
        for line in f:
            spk, utt, env, attack, label = line.strip().split()
            items.append({
                'utt_id': utt,
                'path': str(audio_dir / f'{utt}.flac'),
                'label': 1 if label == 'bonafide' else 0,
            })
    return items


def get_num_frames(path: str) -> int:
    try:
        return int(sf.info(path).frames)
    except Exception:
        wav, _ = sf.read(path)
        return int(len(wav))


class AudioDataset(Dataset):
    def __init__(self, items, max_sec=None, train=False):
        self.items = items
        self.max_len = int(max_sec * 16000) if max_sec else None
        self.train = train
        self.lengths = [min(get_num_frames(x['path']), self.max_len) if self.max_len else get_num_frames(x['path']) for x in items]

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx):
        item = self.items[idx]
        wav, sr = sf.read(item['path'], always_2d=False)
        if wav.ndim > 1:
            wav = wav.mean(axis=1)
        wav = wav.astype(np.float32)
        if sr != 16000:
            raise ValueError(f'Expected 16k audio, got {sr}')
        if self.max_len is not None and len(wav) > self.max_len:
            if self.train:
                start = np.random.randint(0, len(wav) - self.max_len + 1)
            else:
                start = (len(wav) - self.max_len) // 2
            wav = wav[start:start + self.max_len]
        return {'input_values': wav, 'label': item['label']}


class Collator:
    def __init__(self, feature_extractor):
        self.feat = feature_extractor

    def __call__(self, batch):
        wavs = [b['input_values'] for b in batch]
        enc = self.feat(wavs, sampling_rate=16000, return_tensors='pt', padding=True, return_attention_mask=True)
        input_values = enc['input_values']
        attention_mask = enc['attention_mask'] if 'attention_mask' in enc else torch.ones_like(input_values, dtype=torch.long)
        labels = torch.tensor([b['label'] for b in batch], dtype=torch.float32)
        return {'input_values': input_values, 'attention_mask': attention_mask, 'labels': labels}


def compute_eer(labels, scores):
    fpr, tpr, _ = roc_curve(labels, scores, pos_label=1)
    fnr = 1 - tpr
    idx = np.nanargmin(np.abs(fnr - fpr))
    return float((fpr[idx] + fnr[idx]) / 2.0)


@torch.no_grad()
def evaluate(model, loader, device, amp_dtype):
    model.eval()
    all_scores, all_labels = [], []
    for batch in loader:
        x = batch['input_values'].to(device, non_blocking=True)
        m = batch['attention_mask'].to(device, non_blocking=True)
        y = batch['labels'].cpu().numpy()
        with torch.amp.autocast('cuda', dtype=amp_dtype, enabled=device.type == 'cuda'):
            logits = model(x, m)
        all_scores.append(logits.float().cpu().numpy())
        all_labels.append(y)
    scores = np.concatenate(all_scores)
    labels = np.concatenate(all_labels)
    eer = compute_eer(labels, scores)
    acc = float(((scores > 0).astype(np.float32) == labels).mean())
    return {'eer': eer, 'acc': acc}


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_dir', type=str, default=None)
    parser.add_argument('--encoder_name', type=str, default='facebook/wav2vec2-xls-r-300m')
    parser.add_argument('--epochs', type=int, default=4)
    parser.add_argument('--batch_size', type=int, default=24)
    parser.add_argument('--lr_head', type=float, default=1e-3)
    parser.add_argument('--lr_encoder', type=float, default=1e-5)
    parser.add_argument('--weight_decay', type=float, default=1e-4)
    parser.add_argument('--max_sec', type=float, default=6.0)
    parser.add_argument('--num_workers', type=int, default=6)
    parser.add_argument('--seed', type=int, default=1337)
    parser.add_argument('--unfreeze_last_n_layers', type=int, default=4)
    parser.add_argument('--checkpoint', type=str, default='checkpoints/xlsr_ft.pt')
    args = parser.parse_args()

    set_seed(args.seed)
    logger = JsonlLogger()
    data_dir = discover_data_dir(args.data_dir)

    train_items = parse_protocol(data_dir / 'train_protocol.txt', data_dir / 'train/flac')
    dev_items = parse_protocol(data_dir / 'dev_protocol.txt', data_dir / 'dev/flac')

    feature_extractor = AutoFeatureExtractor.from_pretrained(args.encoder_name, local_files_only=True)
    if hasattr(feature_extractor, 'return_attention_mask'):
        feature_extractor.return_attention_mask = True
    feat_dir = Path('artifacts/feature_extractor')
    feat_dir.mkdir(parents=True, exist_ok=True)
    feature_extractor.save_pretrained(feat_dir)

    train_ds = AudioDataset(train_items, max_sec=args.max_sec, train=True)
    dev_ds = AudioDataset(dev_items, max_sec=args.max_sec, train=False)

    train_labels = np.array([x['label'] for x in train_items], dtype=np.int64)
    class_counts = np.bincount(train_labels, minlength=2)
    sample_weights = np.array([1.0 / class_counts[y] for y in train_labels], dtype=np.float64)
    sampler = WeightedRandomSampler(sample_weights, num_samples=len(sample_weights), replacement=True)

    train_loader = DataLoader(
        train_ds,
        batch_size=args.batch_size,
        sampler=sampler,
        num_workers=args.num_workers,
        pin_memory=True,
        persistent_workers=args.num_workers > 0,
        collate_fn=Collator(feature_extractor),
    )
    dev_loader = DataLoader(
        dev_ds,
        batch_sampler=LengthBucketBatchSampler(dev_ds.lengths, batch_size=args.batch_size * 2, shuffle=False),
        num_workers=args.num_workers,
        pin_memory=True,
        persistent_workers=args.num_workers > 0,
        collate_fn=Collator(feature_extractor),
    )

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    amp_dtype = torch.bfloat16 if device.type == 'cuda' and torch.cuda.is_bf16_supported() else torch.float16

    model = build_model(
        encoder_name=args.encoder_name,
        unfreeze_last_n_layers=args.unfreeze_last_n_layers,
    ).to(device)

    enc_params, head_params = [], []
    for n, p in model.named_parameters():
        if not p.requires_grad:
            continue
        if n.startswith('encoder.'):
            enc_params.append(p)
        else:
            head_params.append(p)

    optimizer = torch.optim.AdamW([
        {'params': head_params, 'lr': args.lr_head, 'weight_decay': args.weight_decay},
        {'params': enc_params, 'lr': args.lr_encoder, 'weight_decay': args.weight_decay},
    ])
    total_steps = args.epochs * len(train_loader)
    scheduler = get_cosine_schedule_with_warmup(optimizer, num_warmup_steps=max(10, total_steps // 20), num_training_steps=total_steps)

    pos_weight = torch.tensor([class_counts[0] / max(class_counts[1], 1)], device=device, dtype=torch.float32)

    best_eer = 1.0
    global_step = 0
    Path(args.checkpoint).parent.mkdir(parents=True, exist_ok=True)

    for epoch in range(args.epochs):
        model.train()
        for batch in train_loader:
            x = batch['input_values'].to(device, non_blocking=True)
            m = batch['attention_mask'].to(device, non_blocking=True)
            y = batch['labels'].to(device, non_blocking=True)
            with torch.amp.autocast('cuda', dtype=amp_dtype, enabled=device.type == 'cuda'):
                logits = model(x, m)
                loss = F.binary_cross_entropy_with_logits(logits, y, pos_weight=pos_weight)
            optimizer.zero_grad(set_to_none=True)
            loss.backward()
            torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
            optimizer.step()
            scheduler.step()
            global_step += 1
            if global_step % 50 == 0:
                with torch.no_grad():
                    acc = ((logits > 0).float() == y).float().mean().item()
                logger.log(step=global_step, loss=float(loss.item()), acc=float(acc), epoch=epoch)

        metrics = evaluate(model, dev_loader, device, amp_dtype)
        logger.log(step=global_step, dev_eer=metrics['eer'], dev_acc=metrics['acc'], epoch=epoch)
        if metrics['eer'] < best_eer:
            best_eer = metrics['eer']
            torch.save({
                'model_state': model.state_dict(),
                'encoder_name': args.encoder_name,
                'feature_extractor_name': args.encoder_name,
                'feature_extractor_local_dir': str(feat_dir),
                'model_kwargs': {
                    'encoder_name': args.encoder_name,
                    'unfreeze_last_n_layers': args.unfreeze_last_n_layers,
                },
                'dev_eer': best_eer,
            }, args.checkpoint)

    print(json.dumps({'best_dev_eer': best_eer, 'checkpoint': args.checkpoint, 'data_dir': str(data_dir)}))


if __name__ == '__main__':
    main()
